+/* ========================================
+   MOBILE-FIRST OPTIMIZATIONS
+   ======================================== */
+
+/* Mobile: Better touch targets (minimum 44x44 iOS, 48x48 Material) */
 @media (max-width: 640px) {
+  /* Safe area insets for notched devices - only bottom padding on body */
   body {
     padding-bottom: env(safe-area-inset-bottom);
   }

+  /* Reduced background complexity for mobile performance */
   body::after {
     background-size: 120% 120%, 72px 72px, 72px 72px;
     opacity: 0.5;
   }

+  /* Tighter scroll margin on mobile */
   section[data-section] {
     scroll-margin-top: 80px;
   }

+  /* Subtle hover on mobile (for hybrid devices) */
   .glass-panel:hover {
     transform: translateY(-2px);
   }
+
+  /* Better line height for mobile reading */
+  p, li {
+    line-height: 1.7;
+  }
+
+  /* Larger tap targets for interactive buttons (not inline links) */
+  button:not([class*="inline"]),
+  a[class*="button"],
+  a[class*="rounded-full"],
+  a[class*="rounded-lg"],
+  [role="button"] {
+    min-height: 44px;
+  }
+
+  /* Prevent zoom on input focus (iOS) */
+  input, textarea, select {
+    font-size: 16px !important;
+  }
+}
+
+/* Mobile: Active/touch states */
+@media (max-width: 640px) and (hover: none) {
+  /* Better active states for touch */
+  button:active,
+  a:active {
+    transform: scale(0.97);
+    transition: transform 0.1s ease-out;
+  }
+
+  /* Card press effect */
+  .glass-panel:active,
+  [role="button"]:active {
+    transform: scale(0.98);
+    transition: transform 0.15s ease-out;
+  }
+}
+
+/* Mobile landscape optimizations */
+@media (max-width: 896px) and (orientation: landscape) {
+  /* Reduce vertical spacing in landscape */
+  section[data-section] {
+    padding-top: 2rem;
+    padding-bottom: 2rem;
+  }
+
+  /* Compact header in landscape */
+  header {
+    padding-top: 0.5rem;
+    padding-bottom: 0.5rem;
+  }
+}
+
+/* Mobile: Smooth momentum scrolling */
+@media (max-width: 640px) {
+  /* Apply momentum scrolling only to scrollable containers */
+  .overflow-scroll,
+  .overflow-auto,
+  [style*="overflow: auto"],
+  [style*="overflow: scroll"] {
+    -webkit-overflow-scrolling: touch;
+    scroll-behavior: smooth;
+    overscroll-behavior: contain;
+  }
+}
+
+/* Mobile: Pull-to-refresh spacing */
+@media (max-width: 640px) {
+  body {
+    overscroll-behavior-y: none;
+  }
+}
+
+/* Mobile: Improved focus indicators for keyboard users */
+@media (max-width: 640px) {
+  :focus-visible {
+    outline: 3px solid rgba(56, 189, 248, 0.6);
+    outline-offset: 4px;
+    border-radius: 8px;
+  }
+}
+
+/* Utility class for safe area top padding */
+.safe-top {
+  padding-top: max(1rem, env(safe-area-inset-top));
+}
+
+/* Mobile: Optimized card interactions */
+@media (max-width: 640px) and (hover: none) {
+  /* Project cards - high specificity to override hover states */
+  article[class*="group"]:active,
+  article:active {
+    transform: scale(0.98);
+    transition: transform 0.15s ease-out;
+  }
+
+  /* Links that look like buttons */
+  a[class*="rounded-full"]:active {
+    transform: scale(0.96);
+    transition: transform 0.1s ease-out;
+  }
+}
+
+/* Mobile: Better readability */
+@media (max-width: 640px) {
+  /* Slightly larger body text on mobile */
+  body {
+    font-size: 15px;
+  }
+
+  /* Headers with better mobile sizing */
+  h1 {
+    font-size: 1.875rem; /* 30px */
+    line-height: 1.2;
+  }
+
+  h2 {
+    font-size: 1.5rem; /* 24px */
+    line-height: 1.25;
+  }
+
+  h3 {
+    font-size: 1.125rem; /* 18px */
+    line-height: 1.3;
+  }
+}
+
+/* Mobile: Optimized Three.js scene for performance */
+@media (max-width: 640px) {
+  canvas {
+    /* Reduce canvas quality on lower-end devices */
+    image-rendering: optimizeSpeed;
+  }
+}
+
+/* Mobile: Swipe-friendly spacing */
+@media (max-width: 640px) {
+  /* Add comfortable padding for thumb zones */
+  section {
+    padding-left: max(1rem, env(safe-area-inset-left));
+    padding-right: max(1rem, env(safe-area-inset-right));
